void writePaxHeaders(String entryName, Map<String, String> headers) throws IOException {
    // Build the entry name with appropriate prefix
    String name = "./PaxHeaders.X/" + stripTo7Bits(entryName);

    // Ensure that the name does not exceed the maximum length
    if (name.length() >= TarConstants.NAMELEN) {
        name = name.substring(0, TarConstants.NAMELEN - 1);
    }

    // Create a TarArchiveEntry for the pax header
    TarArchiveEntry pex = new TarArchiveEntry(name, TarConstants.LF_PAX_EXTENDED_HEADER_LC);

    // Use StringWriter to build the header content
    StringWriter w = new StringWriter();
    for (Map.Entry<String, String> h : headers.entrySet()) {
        String key = h.getKey();
        String value = h.getValue();

        // Calculate initial estimated length of the line
        int len = key.length() + value.length() + 3; // blank, equals, and newline

        // Create a line with the format: "length key=value\n"
        String line = len + " " + key + "=" + value + "\n";
        int actualLength = line.getBytes(CharsetNames.UTF_8).length;

        // Adjust the length if the actual length is different from the estimated length
        while (len != actualLength) {
            // Update the length and recreate the line
            len = actualLength;
            line = len + " " + key + "=" + value + "\n";
            actualLength = line.getBytes(CharsetNames.UTF_8).length;
        }

        // Write the line to the StringWriter
        w.write(line);
    }

    // Convert the StringWriter content to byte array
    byte[] data = w.toString().getBytes(CharsetNames.UTF_8);
    pex.setSize(data.length);

    // Add the entry to the archive and write the data
    putArchiveEntry(pex);
    write(data);
    closeArchiveEntry();
}
```

